import type { QAItem } from '../interview-data'

export const TOOLS_MISC_DATA: QAItem[] = [
  // === STATE MANAGEMENT: Redux & RTK (601-615) ===
  { id: 601, category: "State Management", subcategory: "Redux", level: "beginner", q: "Redux là gì? Tại sao chúng ta cần sử dụng Redux?", a: "Redux là thư viện quản lý state tập trung cho JavaScript, thường dùng với React. Nó lưu toàn bộ state ứng dụng trong một store duy nhất, giúp dễ dàng theo dõi, debug và chia sẻ state giữa các component không liên kết trực tiếp." },
  { id: 602, category: "State Management", subcategory: "Redux", level: "beginner", q: "Ba nguyên tắc cốt lõi của Redux là gì?", a: "Ba nguyên tắc: (1) Single source of truth - toàn bộ state trong một store, (2) State is read-only - chỉ thay đổi state qua dispatch action, (3) Changes are made with pure functions - reducer phải là pure function không có side effects." },
  { id: 603, category: "State Management", subcategory: "Redux", level: "beginner", q: "Action trong Redux là gì? Cấu trúc của một action như thế nào?", a: "Action là plain JavaScript object mô tả sự kiện xảy ra trong ứng dụng. Mỗi action bắt buộc có trường `type` (chuỗi định danh) và tùy chọn có `payload` chứa dữ liệu liên quan. Ví dụ: `{ type: 'counter/increment', payload: 1 }`." },
  { id: 604, category: "State Management", subcategory: "Redux", level: "beginner", q: "Reducer trong Redux là gì? Cách viết một reducer đúng chuẩn?", a: "Reducer là pure function nhận state hiện tại và action, trả về state mới. Reducer không được mutate state trực tiếp mà phải tạo bản sao mới. Luôn có default case trả về state hiện tại khi action không khớp." },
  { id: 605, category: "State Management", subcategory: "Redux", level: "beginner", q: "Store trong Redux là gì? Các phương thức chính của store là gì?", a: "Store là nơi lưu trữ toàn bộ state của ứng dụng. Các phương thức chính: `getState()` lấy state hiện tại, `dispatch(action)` gửi action đến reducer, `subscribe(listener)` đăng ký callback khi state thay đổi." },
  { id: 606, category: "State Management", subcategory: "Redux", level: "intermediate", q: "Redux Toolkit (RTK) là gì? Tại sao nên dùng RTK thay vì Redux thuần?", a: "Redux Toolkit là bộ công cụ chính thức giúp đơn giản hóa việc viết Redux. RTK giảm boilerplate code bằng `createSlice`, tích hợp Immer để mutate state trực tiếp, và bao gồm `createAsyncThunk` cho async logic. RTK là cách được khuyến nghị để viết Redux hiện đại." },
  { id: 607, category: "State Management", subcategory: "RTK", level: "intermediate", q: "createSlice trong RTK hoạt động như thế nào?", a: "createSlice tự động tạo action creators và action types từ reducers định nghĩa trong slice. Nó sử dụng Immer bên trong nên bạn có thể viết code 'mutate' state trực tiếp mà vẫn immutable. Trả về object chứa `actions` và `reducer`." },
  { id: 608, category: "State Management", subcategory: "RTK", level: "intermediate", q: "createAsyncThunk được dùng để làm gì? Các trạng thái lifecycle của nó là gì?", a: "createAsyncThunk xử lý async operations trong Redux và tự động dispatch các action theo lifecycle. Ba trạng thái: `pending` (đang thực hiện), `fulfilled` (thành công), `rejected` (thất bại). Dùng `extraReducers` trong slice để xử lý các trạng thái này." },
  { id: 609, category: "State Management", subcategory: "RTK", level: "intermediate", q: "Selector trong Redux là gì? Tại sao nên dùng createSelector?", a: "Selector là function trích xuất và tính toán dữ liệu từ Redux state. createSelector từ Reselect tạo memoized selectors - chỉ tính toán lại khi inputs thay đổi, giúp tránh re-render không cần thiết và cải thiện performance." },
  { id: 610, category: "State Management", subcategory: "RTK", level: "advanced", q: "RTK Query là gì? Lợi ích so với cách fetch data thủ công?", a: "RTK Query là giải pháp data fetching và caching tích hợp trong Redux Toolkit. Nó tự động xử lý loading/error states, caching, cache invalidation, và re-fetching. So với fetch thủ công, RTK Query giảm đáng kể boilerplate và tự động đồng bộ server state với Redux store." },
  { id: 611, category: "State Management", subcategory: "RTK", level: "advanced", q: "Cách định nghĩa API với createApi trong RTK Query như thế nào?", a: "createApi định nghĩa endpoints (queries và mutations) cho một API. Mỗi query tự động tạo hook như `useGetUsersQuery()`. Cấu hình `baseQuery` xác định cách gọi API, `tagTypes` và `providesTags`/`invalidatesTags` quản lý cache invalidation." },
  { id: 612, category: "State Management", subcategory: "Redux", level: "intermediate", q: "Redux middleware là gì? Cho ví dụ về middleware phổ biến?", a: "Middleware là lớp nằm giữa dispatch và reducer, cho phép xử lý side effects, logging, async operations. Middleware phổ biến: `redux-thunk` (xử lý async với function actions), `redux-saga` (generator-based), `redux-logger` (log actions và state changes)." },
  { id: 613, category: "State Management", subcategory: "Redux", level: "advanced", q: "Redux DevTools hoạt động như thế nào? Tính năng time-travel debugging là gì?", a: "Redux DevTools là browser extension cho phép inspect toàn bộ lịch sử actions và state changes. Time-travel debugging cho phép nhảy đến bất kỳ thời điểm nào trong lịch sử để xem state tại thời điểm đó, giúp debug lỗi cực kỳ hiệu quả." },
  { id: 614, category: "State Management", subcategory: "Redux", level: "intermediate", q: "useSelector và useDispatch hook trong React-Redux hoạt động như thế nào?", a: "useSelector nhận selector function và trả về giá trị từ Redux store, tự động re-render khi giá trị thay đổi. useDispatch trả về hàm dispatch để gửi actions. Cả hai hooks thay thế Higher Order Component `connect()` của React-Redux cũ." },
  { id: 615, category: "State Management", subcategory: "Redux", level: "advanced", q: "Khi nào nên dùng Redux và khi nào không cần?", a: "Nên dùng Redux khi: state cần chia sẻ giữa nhiều component không liên quan, state phức tạp cần được theo dõi (audit log), logic update state phức tạp. Không cần khi: app nhỏ, state chủ yếu local component, hoặc React Query/Zustand đủ đáp ứng nhu cầu." },

  // === STATE MANAGEMENT: Zustand (616-625) ===
  { id: 616, category: "State Management", subcategory: "Zustand", level: "beginner", q: "Zustand là gì? So sánh với Redux về độ phức tạp?", a: "Zustand là thư viện quản lý state nhỏ gọn cho React, không yêu cầu boilerplate như Redux. API đơn giản dựa trên hooks, không cần Provider wrapper, không có actions/reducers riêng biệt. Bundle size chỉ ~1KB so với Redux ~10KB." },
  { id: 617, category: "State Management", subcategory: "Zustand", level: "beginner", q: "Cách tạo một store với Zustand như thế nào?", a: "Dùng hàm `create` từ zustand, truyền vào function nhận `set` và trả về object chứa state và actions. Actions gọi `set()` để cập nhật state. Store được dùng như hook trong component: `const count = useStore(state => state.count)`." },
  { id: 618, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Cách định nghĩa actions trong Zustand store?", a: "Actions trong Zustand là các function được định nghĩa cùng state trong object trả về từ `create`. Gọi `set()` bên trong action để cập nhật state, có thể dùng `set(state => ({ count: state.count + 1 }))` để access state hiện tại." },
  { id: 619, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Zustand khác Redux như thế nào về kiến trúc?", a: "Zustand không có khái niệm actions/reducers/dispatching riêng biệt - tất cả nằm trong store function. Không cần Provider, không cần combineReducers, không cần middleware phức tạp. State updates trực tiếp qua set(), ít boilerplate hơn nhiều." },
  { id: 620, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Làm thế nào để tránh re-render không cần thiết trong Zustand?", a: "Dùng selector function khi truy cập store: `useStore(state => state.count)` thay vì `useStore()`. Component chỉ re-render khi giá trị được select thay đổi. Dùng `shallow` equality từ zustand/shallow để so sánh objects/arrays." },
  { id: 621, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "Zustand middleware là gì? Cho ví dụ về devtools middleware?", a: "Zustand middleware wrap store creator để thêm functionality. Middleware `devtools` kết nối store với Redux DevTools để debug. Middleware `immer` cho phép mutate state trực tiếp. Middleware `persist` lưu state vào localStorage/sessionStorage." },
  { id: 622, category: "State Management", subcategory: "Zustand", level: "intermediate", q: "persist middleware trong Zustand hoạt động như thế nào?", a: "Middleware `persist` từ `zustand/middleware` tự động lưu state vào storage (localStorage mặc định) và khôi phục khi app reload. Cấu hình `name` (key trong storage), `partialize` để chọn phần state cần persist, và `storage` để dùng sessionStorage hoặc custom storage." },
  { id: 623, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Cách chia nhỏ Zustand store thành nhiều slices?", a: "Zustand hỗ trợ pattern chia store thành slices bằng cách tạo các slice functions riêng biệt và combine chúng trong `create`. Mỗi slice nhận `set`, `get`, `api` và trả về phần state của mình. Giúp code tổ chức tốt hơn với store lớn." },
  { id: 624, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Cách sử dụng Zustand với TypeScript để có type safety?", a: "Định nghĩa interface cho state và actions, dùng generic trong `create<StoreType>()`. Từ Zustand v4, dùng pattern `create<T>()((set, get) => ({...}))` hoặc `createStore<T>`. TypeScript tự động infer types khi dùng selector." },
  { id: 625, category: "State Management", subcategory: "Zustand", level: "advanced", q: "Khi nào nên chọn Zustand thay vì Redux Toolkit?", a: "Chọn Zustand khi: app vừa/nhỏ, ưu tiên đơn giản và ít boilerplate, không cần time-travel debugging phức tạp. Chọn RTK khi: team quen Redux, cần RTK Query, app lớn với nhiều developer, cần audit log actions đầy đủ." },

  // === STATE MANAGEMENT: React Query (626-640) ===
  { id: 626, category: "State Management", subcategory: "React Query", level: "beginner", q: "React Query (TanStack Query) là gì? Mục đích chính của nó là gì?", a: "React Query (nay là TanStack Query v5) là thư viện quản lý server state cho React, giải quyết bài toán mà useState + useEffect không làm tốt: fetching, caching, synchronizing và updating data từ API. Ví dụ thực tế: không cần React Query, bạn phải tự viết loading state, error handling, cache, deduplication, refetch khi focus window, retry khi fail — React Query làm tất cả tự động. Khác biệt cốt lõi với Redux: Redux quản lý client state (UI state, form state), React Query quản lý server state (data từ API có thể thay đổi bởi người khác bất kỳ lúc nào). Trong thực tế, 80% Redux code trong các dự án là để fetch và cache API data — React Query thay thế hoàn toàn phần đó." },
  { id: 627, category: "State Management", subcategory: "React Query", level: "beginner", q: "useQuery hook hoạt động như thế nào? Các tham số cơ bản là gì?", a: "useQuery là hook chính để đọc data, nhận 2 tham số bắt buộc: `queryKey` (mảng định danh duy nhất, ví dụ `['todos', { status: 'active' }]`) và `queryFn` (async function trả về data, ví dụ `() => fetch('/api/todos').then(r => r.json())`). Trả về object gồm: `data` (kết quả), `isLoading` (true lần fetch đầu), `isFetching` (true khi đang fetch kể cả background), `isError`/`error` (lỗi), `isSuccess`, `status`. Cơ chế: component mount → check cache theo queryKey → nếu có data fresh thì dùng luôn, nếu stale thì vừa show cached data vừa refetch background. Đây là pattern stale-while-revalidate." },
  { id: 628, category: "State Management", subcategory: "React Query", level: "intermediate", q: "useMutation hook dùng để làm gì? Cách xử lý optimistic updates?", a: "useMutation xử lý write operations (POST/PUT/DELETE) — khác useQuery chỉ đọc. Cung cấp `mutate()` (fire-and-forget) hoặc `mutateAsync()` (trả về Promise). States: `isPending`, `isError`, `isSuccess`, `data`, `error`. Optimistic update flow: (1) `onMutate`: cancel ongoing queries, snapshot data cũ, set cache mới ngay → UI cập nhật tức thì. (2) `onError`: nhận snapshot từ onMutate context, rollback cache. (3) `onSettled`: invalidate queries để sync với server. Ví dụ thực tế: user like bài viết → heart đỏ ngay lập tức (optimistic), nếu API fail → rollback heart về trắng." },
  { id: 629, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cache invalidation trong React Query hoạt động như thế nào?", a: "Cache invalidation là cơ chế đánh dấu data đã cũ (stale) để trigger refetch. Cách dùng: `queryClient.invalidateQueries({ queryKey: ['todos'] })` — tất cả queries có key bắt đầu bằng 'todos' bị đánh dấu stale. Nếu component đang mount thì refetch ngay, nếu không thì refetch khi component mount lại. Thường gọi sau mutation thành công: thêm todo mới → invalidate todo list → list tự động refetch. Ngoài ra có `queryClient.setQueryData()` để update cache trực tiếp mà không cần refetch — hữu ích khi mutation trả về data mới." },
  { id: 630, category: "State Management", subcategory: "React Query", level: "intermediate", q: "staleTime và gcTime (cacheTime) trong React Query là gì? Sự khác biệt?", a: "Hai config quan trọng nhất quyết định caching behavior. **staleTime** (mặc định 0): thời gian data được coi là 'fresh' — trong khoảng này component mount mới sẽ dùng cached data mà KHÔNG refetch. Ví dụ: `staleTime: 5 * 60 * 1000` (5 phút) → trong 5 phút, navigate qua lại giữa các page sẽ show cached data ngay, không loading. **gcTime** (mặc định 5 phút): thời gian data ở lại trong cache SAU KHI không còn component nào subscribe. Khi hết gcTime, data bị xóa khỏi memory. Quan hệ: staleTime quyết định 'khi nào refetch', gcTime quyết định 'khi nào xóa cache'. staleTime nên ≤ gcTime." },
  { id: 631, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Tại sao React Query được coi là giải pháp 'server state' không phải 'global state'?", a: "Có 2 loại state khác biệt bản chất: **Client state** (theme, sidebar open, form input) — thuộc sở hữu hoàn toàn của client, đồng bộ ngay lập tức, không bao giờ 'stale'. **Server state** (user profile, todo list, product catalog) — thuộc sở hữu của server, có thể bị thay đổi bởi người khác, cần đồng bộ liên tục, luôn có khả năng 'stale'. Redux trộn lẫn 2 loại này vào 1 store, dẫn đến phức tạp không cần thiết (loading states, error states, normalization). React Query tách biệt: nó CHỈ quản lý server state với caching, background refetch, retry, deduplication. Client state dùng useState/useReducer/Zustand. Kết quả: giảm 50-80% Redux code trong hầu hết projects." },
  { id: 632, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách cấu hình React Query với QueryClient và QueryClientProvider?", a: "Tạo `QueryClient` instance với defaultOptions và wrap app bằng `QueryClientProvider`. Có thể cấu hình global staleTime, gcTime, retry attempts. Dùng `useQueryClient()` hook để access QueryClient trong component." },
  { id: 633, category: "State Management", subcategory: "React Query", level: "intermediate", q: "refetchOnWindowFocus trong React Query là gì? Khi nào nên tắt nó?", a: "refetchOnWindowFocus là behavior mặc định: khi user chuyển tab rồi quay lại, React Query tự động refetch tất cả stale queries. Mục đích: đảm bảo data luôn fresh — ví dụ user đang xem dashboard, chuyển qua Slack 5 phút, quay lại thì data cập nhật mới nhất. Nên tắt (`refetchOnWindowFocus: false`) khi: (1) data ít thay đổi (config, static content), (2) refetch gây UX tệ (reset scroll, flash loading), (3) API có rate limit. Có thể set global qua `defaultOptions` hoặc per-query. Tương tự có `refetchOnReconnect` (khi mạng khôi phục) và `refetchInterval` (polling định kỳ)." },
  { id: 634, category: "State Management", subcategory: "React Query", level: "advanced", q: "Prefetching trong React Query hoạt động như thế nào?", a: "Dùng `queryClient.prefetchQuery()` để fetch và cache data trước khi user cần. Ví dụ: hover trên link thì prefetch page data. Server-side dùng `dehydrate`/`HydrationBoundary` để truyền prefetched data từ server xuống client." },
  { id: 635, category: "State Management", subcategory: "React Query", level: "advanced", q: "Infinite queries trong React Query là gì? Dùng cho pagination như thế nào?", a: "`useInfiniteQuery` là hook chuyên biệt cho infinite scroll và load-more pagination — thay vì fetch 1 page, nó quản lý nhiều pages trong 1 query. Cấu hình: `queryFn` nhận `pageParam` (cursor hoặc page number), `getNextPageParam` trả về param cho page tiếp theo (return undefined khi hết data). Kết quả: `data.pages` là mảng chứa data từng page, `data.pageParams` lưu params đã dùng. Gọi `fetchNextPage()` khi user scroll tới cuối (dùng IntersectionObserver). Ví dụ: social feed, product listing, chat history. Có thêm `fetchPreviousPage()` cho bi-directional infinite scroll." },
  { id: 636, category: "State Management", subcategory: "React Query", level: "advanced", q: "Dependent queries trong React Query là gì?", a: "Dependent query (hay serial query) là query mà việc thực thi phụ thuộc vào kết quả của query khác. Dùng `enabled` option để kiểm soát: ví dụ fetch user trước, rồi mới fetch posts của user đó — `useQuery({ queryKey: ['posts', userId], queryFn: () => fetchPosts(userId), enabled: !!userId })`. Khi userId chưa có (query user chưa xong), enabled = false nên posts query không chạy. Khi userId có giá trị, enabled = true → tự động fetch. React Query handle loading states đúng cho cả chain: component thấy isLoading = true cho tới khi query cuối cùng hoàn thành. Tránh lạm dụng dependent queries vì tạo waterfall — nếu queries độc lập, chạy parallel tốt hơn." },
  { id: 637, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách xử lý error trong React Query?", a: "useQuery trả về `isError` và `error` khi query thất bại. Cấu hình `retry` (số lần retry, mặc định 3) và `retryDelay`. Dùng `onError` callback hoặc Error Boundary để xử lý errors. `throwOnError: true` để throw error cho Error Boundary bắt." },
  { id: 638, category: "State Management", subcategory: "React Query", level: "intermediate", q: "QueryKey trong React Query nên được thiết kế như thế nào?", a: "QueryKey nên bao gồm tất cả dependencies của query (như filters, pagination, user ID). Dùng mảng thay vì string: `['todos', { status: 'active', page: 1 }]`. React Query tự động invalidate khi bất kỳ phần nào của key thay đổi." },
  { id: 639, category: "State Management", subcategory: "React Query", level: "advanced", q: "Optimistic updates trong React Query thực hiện như thế nào?", a: "Trong `onMutate`: lưu snapshot của data hiện tại, dùng `queryClient.setQueryData()` để cập nhật cache ngay lập tức. Trong `onError`: dùng snapshot để rollback. Trong `onSettled`: invalidate query để đồng bộ với server." },
  { id: 640, category: "State Management", subcategory: "React Query", level: "advanced", q: "Cách kết hợp React Query với Next.js Server Components?", a: "Dùng `@tanstack/react-query` với Next.js bằng pattern `dehydrate`/`HydrationBoundary`. Fetch data trên server với `prefetchQuery`, serialize với `dehydrate`, wrap Client Components bằng `HydrationBoundary` để inject cached data." },

  // === STATE MANAGEMENT: React Query Nâng Cao (1056-1070) ===
  { id: 1056, category: "State Management", subcategory: "React Query", level: "beginner", q: "QueryClientProvider là gì? Tại sao cần wrap app bằng nó?", a: "QueryClientProvider là React Context Provider cung cấp QueryClient instance cho toàn bộ component tree. QueryClient là 'bộ não' quản lý cache, chứa tất cả cached data, query states, và config. Mọi `useQuery`/`useMutation` bên trong đều cần access QueryClient. Setup: tạo `const queryClient = new QueryClient()` BÊN NGOÀI component (tránh re-create mỗi render), wrap app bằng `<QueryClientProvider client={queryClient}>`. Có thể cấu hình defaultOptions cho tất cả queries: `new QueryClient({ defaultOptions: { queries: { staleTime: 60_000, retry: 2 } } })`. Trong Next.js App Router, đặt ở root layout nhưng cần 'use client' wrapper." },
  { id: 1057, category: "State Management", subcategory: "React Query", level: "beginner", q: "Sự khác biệt giữa isLoading và isFetching trong useQuery?", a: "Đây là câu phỏng vấn rất phổ biến. **isLoading** (hay `status === 'pending'`): true CHỈ khi fetch lần đầu VÀ chưa có cached data — dùng để show loading skeleton/spinner toàn trang. **isFetching**: true MỌI KHI đang fetch, kể cả background refetch khi đã có cached data — dùng để show subtle indicator (spinning icon nhỏ, progress bar mờ). Ví dụ thực tế: user vào trang Products lần đầu → isLoading=true, show skeleton. User navigate đi rồi quay lại → có cached data nên isLoading=false (show data cũ ngay), nhưng isFetching=true (đang refetch background). Thêm `isRefetching` = isFetching && !isLoading (đang refetch có data cũ)." },
  { id: 1058, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Placeholder data và initial data trong React Query khác gì nhau?", a: "`placeholderData` là data tạm hiển thị trong khi fetch, không lưu vào cache, `isPlaceholderData` flag = true. `initialData` được coi như real cached data, có `dataUpdatedAt` timestamp, ảnh hưởng staleTime. Dùng placeholderData cho UX, initialData khi có data thật từ nguồn khác." },
  { id: 1059, category: "State Management", subcategory: "React Query", level: "intermediate", q: "select option trong useQuery dùng để làm gì?", a: "`select` transform data trả về từ queryFn trước khi component nhận. Chỉ re-render khi selected data thay đổi (shallow compare). Ví dụ: `select: (data) => data.filter(t => t.done)` giúp component chỉ re-render khi filtered list thay đổi, không phải toàn bộ data." },
  { id: 1060, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Parallel queries và useQueries trong React Query là gì?", a: "Parallel queries là kỹ thuật fetch nhiều API endpoints cùng lúc thay vì tuần tự (waterfall). Cách 1: gọi nhiều `useQuery` hooks trong cùng component — React Query tự động chạy chúng parallel. Cách 2: `useQueries` hook nhận mảng query configs, hữu ích khi số lượng queries dynamic (ví dụ fetch details cho danh sách product IDs). Kết quả trả về mảng objects, mỗi object giống useQuery result. Ví dụ: dashboard cần user info + notifications + stats → 3 useQuery hooks chạy song song, tổng thời gian = query chậm nhất (thay vì cộng dồn). Lưu ý: React Suspense mode sẽ waterfall nếu mỗi query ở component khác nhau — dùng `useSuspenseQueries` để parallel trong Suspense." },
  { id: 1061, category: "State Management", subcategory: "React Query", level: "intermediate", q: "Cách cancel queries trong React Query khi component unmount?", a: "React Query tự động cancel query khi component unmount nếu dùng `AbortSignal`. queryFn nhận `signal` parameter: `queryFn: ({ signal }) => fetch(url, { signal })`. Khi unmount, React Query gọi abort trên signal. Giảm unnecessary network requests." },
  { id: 1062, category: "State Management", subcategory: "React Query", level: "advanced", q: "Query Filters trong React Query là gì? Dùng ở đâu?", a: "Query Filters là pattern matching system cho phép target nhóm queries khi thao tác hàng loạt. Dùng trong `invalidateQueries`, `refetchQueries`, `removeQueries`, `cancelQueries`. Filter options: `queryKey` (fuzzy match — `['todos']` match cả `['todos', 1]`), `type` ('active' = đang có subscriber, 'inactive' = cached nhưng không ai dùng, 'all'), `stale` (true/false), `fetchStatus` ('fetching'/'paused'/'idle'). Ví dụ thực tế: user logout → `queryClient.removeQueries({ type: 'all' })` xóa toàn bộ cache. Hoặc: mutation thành công → `invalidateQueries({ queryKey: ['todos'], type: 'active' })` chỉ refetch todos đang hiển thị." },
  { id: 1063, category: "State Management", subcategory: "React Query", level: "advanced", q: "useSuspenseQuery khác gì useQuery? Khi nào dùng?", a: "`useSuspenseQuery` tích hợp React Suspense — thay vì return `isLoading`/`isError`, nó throw Promise (cho Suspense boundary bắt) hoặc throw Error (cho Error Boundary bắt). Kết quả: `data` luôn defined (TypeScript happy), không cần if/else cho loading/error states. Code gọn hơn: component chỉ chứa happy path. Suspense boundary ở parent xử lý loading, ErrorBoundary xử lý error. Khi nào dùng: project đã adopt Suspense pattern, muốn tách loading UI khỏi component logic. Khi nào KHÔNG dùng: cần kiểm soát loading state chi tiết, cần show partial data trong khi fetch. Lưu ý: nhiều useSuspenseQuery trong 1 component sẽ waterfall — dùng `useSuspenseQueries` để parallel." },
  { id: 1064, category: "State Management", subcategory: "React Query", level: "advanced", q: "persistQueryClient trong React Query dùng để làm gì?", a: "Persist cache data vào localStorage/AsyncStorage/IndexedDB để restore khi user reload page. Dùng `@tanstack/query-persist-client-core` + `persistQueryClient()`. Cấu hình `maxAge` để giới hạn thời gian data được restore. Cải thiện UX bằng cách show cached data ngay lập tức." },
  { id: 1065, category: "State Management", subcategory: "React Query", level: "advanced", q: "Mutation side effects: onMutate, onSuccess, onError, onSettled hoạt động ra sao?", a: "`onMutate`: chạy trước mutation, dùng cho optimistic update, return context cho onError. `onSuccess`: chạy khi thành công. `onError`: chạy khi thất bại, nhận context từ onMutate để rollback. `onSettled`: luôn chạy cuối cùng (như finally), thường dùng để invalidate queries." },
  { id: 1066, category: "State Management", subcategory: "React Query", level: "intermediate", q: "keepPreviousData (placeholderData với identity function) dùng khi nào?", a: "Dùng `placeholderData: (prev) => prev` để giữ data cũ khi queryKey thay đổi (ví dụ pagination, filter). Tránh flash loading state khi chuyển page. `isPlaceholderData` flag cho biết đang show data cũ. UX mượt hơn nhiều so với show loading mỗi lần." },
  { id: 1067, category: "State Management", subcategory: "React Query", level: "advanced", q: "React Query DevTools là gì? Cách sử dụng?", a: "React Query DevTools (`@tanstack/react-query-devtools`) là công cụ debug chuyên dụng, hiển thị floating panel trong browser. Tính năng: xem tất cả queries và trạng thái real-time (fresh/stale/inactive/fetching), inspect cached data dạng JSON tree, xem query timing (khi nào fetch, bao lâu), manual trigger refetch/invalidate/remove/reset từng query, xem subscribers count. Setup: `import { ReactQueryDevtools } from '@tanstack/react-query-devtools'` → đặt `<ReactQueryDevtools initialIsOpen={false} />` bên trong QueryClientProvider. Tự động ẩn trong production build (tree-shaken). Rất hữu ích khi debug cache issues: tại sao data stale, query nào đang fetch, cache hit hay miss. Là 1 trong những lý do developer chọn React Query — visibility vào cache layer mà Redux DevTools không cho." },
  { id: 1068, category: "State Management", subcategory: "React Query", level: "advanced", q: "Cách xử lý race conditions trong React Query?", a: "React Query tự động handle race conditions: khi component re-render với queryKey mới, query cũ bị cancel (nếu dùng AbortSignal), chỉ data từ query mới nhất được sử dụng. Không cần manual cleanup hay useEffect dependencies tracking." },
  { id: 1069, category: "State Management", subcategory: "React Query", level: "intermediate", q: "enabled option trong useQuery dùng để làm gì?", a: "`enabled: false` ngăn query tự động chạy. Dùng cho: dependent queries (`enabled: !!userId`), lazy queries (chỉ fetch khi user trigger), conditional fetching. Khi enabled chuyển từ false sang true, query tự động fetch." },
  { id: 1070, category: "State Management", subcategory: "React Query", level: "advanced", q: "So sánh React Query với SWR? Khi nào chọn cái nào?", a: "React Query: nhiều features hơn (mutations, infinite queries, devtools, prefetching, offline support), API phức tạp hơn. SWR: nhẹ hơn, đơn giản hơn, tích hợp tốt với Next.js. Chọn React Query cho app phức tạp cần mutations/optimistic updates. Chọn SWR cho app đơn giản chỉ cần data fetching." },

  // === STATE MANAGEMENT: Recoil & Jotai (641-650) ===
  { id: 641, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Recoil là gì? Khái niệm atom trong Recoil là gì?", a: "Recoil là thư viện state management từ Meta, theo mô hình atomic state. Atom là đơn vị state nhỏ nhất, độc lập, có thể subscribe riêng lẻ. Component subscribing atom chỉ re-render khi atom đó thay đổi, không re-render toàn bộ như Redux." },
  { id: 642, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Selector trong Recoil là gì? Khác gì với atom?", a: "Selector là derived state, tính toán từ atoms hoặc selectors khác. Là pure function, tự động re-compute khi dependencies thay đổi và cũng có caching. Dùng `useRecoilValue()` để đọc selector, không thể write trực tiếp (trừ writeable selectors)." },
  { id: 643, category: "State Management", subcategory: "Recoil", level: "intermediate", q: "Cách đọc và ghi atom trong Recoil component?", a: "Dùng `useRecoilState(atom)` để vừa đọc vừa ghi (như useState). `useRecoilValue(atom)` chỉ đọc. `useSetRecoilState(atom)` chỉ ghi. Component không subscribe vào atom sẽ không re-render khi atom thay đổi." },
  { id: 644, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Jotai là gì? So sánh với Recoil?", a: "Jotai là thư viện atomic state management tương tự Recoil nhưng nhỏ gọn hơn (~3KB vs ~21KB). API đơn giản hơn: không cần key string cho atoms, không cần RecoilRoot. Jotai dùng WeakMap để track atoms thay vì global key registry như Recoil." },
  { id: 645, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Cách tạo và sử dụng atom trong Jotai?", a: "Dùng `atom(initialValue)` để tạo atom. Trong component dùng `useAtom(myAtom)` trả về `[value, setValue]` như useState. Derived atoms: `atom(get => get(atomA) + get(atomB))`. Jotai đủ nhỏ để dùng ngay không cần Provider." },
  { id: 646, category: "State Management", subcategory: "Jotai", level: "advanced", q: "Async atoms trong Jotai hoạt động như thế nào?", a: "Jotai hỗ trợ async atoms bằng cách trả về Promise trong atom getter. Component tự động suspend khi atom đang fetch (kết hợp React Suspense). Dùng `loadable()` để xử lý loading state mà không cần Suspense." },
  { id: 647, category: "State Management", subcategory: "Recoil", level: "advanced", q: "AtomFamily và selectorFamily trong Recoil là gì?", a: "atomFamily tạo factory function cho atoms - mỗi parameter tạo một atom riêng biệt. Dùng khi cần state cho từng item trong danh sách (ví dụ: `todoItemAtom(id)`). selectorFamily tương tự nhưng cho selectors có tham số." },
  { id: 648, category: "State Management", subcategory: "Recoil", level: "advanced", q: "So sánh bundle size và performance giữa Recoil, Jotai và Zustand?", a: "Bundle size: Jotai ~3KB < Zustand ~8KB < Recoil ~21KB. Performance: tất cả đều fine-grained (chỉ re-render component subscribe). Jotai và Zustand phù hợp app cần bundle nhỏ. Recoil phù hợp khi cần ecosystem Facebook và async selector mạnh." },
  { id: 649, category: "State Management", subcategory: "Jotai", level: "intermediate", q: "Jotai Provider là gì? Khi nào cần dùng?", a: "Jotai hoạt động không cần Provider (global store mặc định). Provider tạo isolated scope riêng cho atoms - hữu ích khi muốn reset atoms khi unmount hoặc tạo nhiều instance độc lập (ví dụ testing, micro-frontend)." },
  { id: 650, category: "State Management", subcategory: "Recoil", level: "advanced", q: "Khi nào nên dùng atomic state management (Recoil/Jotai) thay vì Redux/Zustand?", a: "Atomic state phù hợp khi: có nhiều pieces of state độc lập cần quản lý riêng, cần fine-grained subscriptions để optimize re-renders, hoặc state có cấu trúc graph phức tạp. Redux/Zustand phù hợp hơn khi cần single centralized store với actions rõ ràng." },

  // === NODE.JS: Cơ Bản (651-660) ===
  { id: 651, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Node.js là gì? Điểm khác biệt với JavaScript trên trình duyệt?", a: "Node.js là runtime environment cho JavaScript chạy trên server, xây dựng trên V8 engine của Chrome. Khác biệt: không có DOM/BOM/window object, nhưng có access đến filesystem, network, OS. Sử dụng CommonJS/ESM modules thay vì browser script tags." },
  { id: 652, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "V8 engine là gì? Vai trò của nó trong Node.js?", a: "V8 là JavaScript engine mã nguồn mở của Google, viết bằng C++. V8 biên dịch JavaScript thành native machine code thay vì interpret từng dòng, giúp tốc độ thực thi rất nhanh. Node.js nhúng V8 vào C++ runtime để chạy JS ngoài trình duyệt." },
  { id: 653, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Event-driven architecture trong Node.js nghĩa là gì?", a: "Node.js hoạt động theo mô hình event-driven: thay vì chờ đợi I/O operations hoàn thành, Node.js đăng ký event listeners và tiếp tục xử lý. Khi I/O xong, event được emit và callback được gọi. Mô hình này phù hợp cho ứng dụng với nhiều concurrent connections." },
  { id: 654, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "Non-blocking I/O trong Node.js là gì? Tại sao quan trọng?", a: "Non-blocking I/O: khi thực hiện I/O (đọc file, query DB, HTTP request), Node.js không chờ mà tiếp tục xử lý requests khác. Khi I/O xong, callback được đưa vào event queue. Điều này cho phép single-threaded Node.js xử lý hàng nghìn concurrent connections hiệu quả." },
  { id: 655, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "npm là gì? Phân biệt npm install, npm install --save-dev?", a: "npm (Node Package Manager) là công cụ quản lý packages cho Node.js. `npm install package` cài package vào `dependencies` (cần cho production). `npm install --save-dev package` cài vào `devDependencies` (chỉ cần khi development như Jest, TypeScript)." },
  { id: 656, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "package.json là gì? Các trường quan trọng trong package.json?", a: "package.json là file metadata của Node.js project, chứa thông tin về project và dependencies. Trường quan trọng: `name`, `version`, `scripts` (npm commands), `dependencies`, `devDependencies`, `main`/`module` (entry point), `engines` (Node version)." },
  { id: 657, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "package-lock.json là gì? Tại sao nên commit file này?", a: "package-lock.json lưu exact versions của tất cả dependencies (kể cả transitive). Đảm bảo `npm install` trên các máy khác nhau cài đúng cùng version. Nên commit vào git để tránh 'works on my machine' bugs do version differences." },
  { id: 658, category: "Node.js", subcategory: "Cơ Bản", level: "beginner", q: "CommonJS modules (require/module.exports) và ES Modules (import/export) trong Node.js khác nhau như thế nào?", a: "CommonJS là hệ thống module cũ của Node.js: `require()` để import, `module.exports` để export, load synchronous. ES Modules là chuẩn mới: `import`/`export`, load asynchronous, tree-shakeable. Node.js hỗ trợ cả hai, ESM cần file `.mjs` hoặc `type: module` trong package.json." },
  { id: 659, category: "Node.js", subcategory: "Cơ Bản", level: "intermediate", q: "process object trong Node.js cung cấp những gì?", a: "process là global object cung cấp thông tin và control về Node.js process hiện tại. Quan trọng: `process.env` (biến môi trường), `process.argv` (command line arguments), `process.exit()`, `process.cwd()`, `process.pid`, `process.on('uncaughtException')` xử lý unhandled errors." },
  { id: 660, category: "Node.js", subcategory: "Cơ Bản", level: "intermediate", q: "Sự khác biệt giữa __dirname và __filename trong Node.js?", a: "__dirname là đường dẫn tuyệt đối đến thư mục chứa file hiện tại. __filename là đường dẫn tuyệt đối đến file hiện tại. Trong ES Modules không có __dirname, cần dùng `import.meta.url` với `fileURLToPath` để tương đương." },

  // === NODE.JS: Event Loop & Async (661-670) ===
  { id: 661, category: "Node.js", subcategory: "Event Loop", level: "intermediate", q: "Event loop trong Node.js hoạt động như thế nào?", a: "Event loop là cơ chế cho phép Node.js thực hiện non-blocking I/O mặc dù single-threaded. Các phases: timers (setTimeout/setInterval), pending callbacks, idle/prepare, poll (I/O callbacks), check (setImmediate), close callbacks. Mỗi vòng lặp chạy qua các phases theo thứ tự." },
  { id: 662, category: "Node.js", subcategory: "Event Loop", level: "intermediate", q: "Sự khác biệt giữa setTimeout(fn, 0) và setImmediate() là gì?", a: "setImmediate() chạy trong check phase (sau poll phase). setTimeout(fn, 0) chạy trong timers phase (vòng loop tiếp theo). Trong main module, thứ tự không đảm bảo. Nhưng trong I/O callback, setImmediate luôn chạy trước setTimeout(fn, 0)." },
  { id: 663, category: "Node.js", subcategory: "Event Loop", level: "advanced", q: "process.nextTick() khác setImmediate() như thế nào?", a: "process.nextTick() chạy ngay sau operation hiện tại, trước khi event loop tiếp tục - không phải một phase của event loop. setImmediate() chạy trong check phase của event loop. nextTick callbacks luôn chạy trước setImmediate callbacks. Dùng nextTick cẩn thận để tránh starve event loop." },
  { id: 664, category: "Node.js", subcategory: "Async", level: "intermediate", q: "Callback hell là gì? Cách giải quyết?", a: "Callback hell (pyramid of doom) là tình trạng callback lồng nhau nhiều cấp, khó đọc và maintain. Giải pháp: (1) Named functions thay vì anonymous, (2) Promises để chain, (3) async/await để viết async code như synchronous, (4) Error-first callback convention." },
  { id: 665, category: "Node.js", subcategory: "Async", level: "intermediate", q: "Promise trong Node.js hoạt động như thế nào? Các states của Promise?", a: "Promise đại diện cho giá trị chưa có ngay lập tức. Ba states: `pending` (đang chờ), `fulfilled` (thành công với value), `rejected` (thất bại với reason). Dùng `.then()` xử lý fulfilled, `.catch()` xử lý rejected, `.finally()` chạy bất kể kết quả." },
  { id: 666, category: "Node.js", subcategory: "Async", level: "intermediate", q: "async/await trong Node.js là gì? Lợi ích so với Promise chains?", a: "async/await là syntactic sugar trên Promise, cho phép viết async code theo cú pháp synchronous. `async` function luôn trả về Promise. `await` tạm dừng execution cho đến khi Promise resolved. Dễ đọc hơn, dễ debug hơn, xử lý error bằng try/catch tự nhiên." },
  { id: 667, category: "Node.js", subcategory: "Streams", level: "advanced", q: "Streams trong Node.js là gì? Có những loại stream nào?", a: "Stream là interface xử lý data theo từng chunks thay vì load toàn bộ vào memory. Bốn loại: Readable (đọc data), Writable (ghi data), Duplex (đọc và ghi), Transform (transform data trong khi đọc/ghi). Ví dụ: HTTP requests, file I/O, gzip compression." },
  { id: 668, category: "Node.js", subcategory: "Streams", level: "advanced", q: "pipe() trong Node.js streams là gì?", a: "pipe() kết nối Readable stream với Writable stream, tự động quản lý flow và backpressure. Dữ liệu chảy từ source đến destination theo chunks, không cần load toàn bộ vào memory. Ví dụ: `fs.createReadStream('file').pipe(gzip).pipe(response)` để stream file nén đến HTTP response." },
  { id: 669, category: "Node.js", subcategory: "Buffers", level: "intermediate", q: "Buffer trong Node.js là gì? Khi nào cần dùng?", a: "Buffer là class built-in để xử lý binary data trong Node.js. JavaScript không có binary data type, Buffer lấp đầy khoảng trống này. Cần dùng khi: đọc file binary, xử lý network packets, mã hóa/giải mã base64, làm việc với streams." },
  { id: 670, category: "Node.js", subcategory: "Event Loop", level: "advanced", q: "Libuv là gì? Vai trò trong Node.js?", a: "Libuv là C library cung cấp event loop, async I/O, và thread pool cho Node.js. Thread pool (4 threads mặc định) xử lý các I/O operations mà OS không hỗ trợ async như DNS lookup, file I/O. Libuv abstract sự khác biệt giữa các OS (Windows, Linux, macOS)." },

  // === NODE.JS: HTTP & Express (671-680) ===
  { id: 671, category: "Node.js", subcategory: "HTTP", level: "beginner", q: "Cách tạo HTTP server với module http trong Node.js?", a: "Dùng `http.createServer((req, res) => {...})` tạo server và `.listen(port)` để lắng nghe. `req` chứa request info (method, url, headers), `res` dùng để gửi response với `res.writeHead()` và `res.end()`. Module http là built-in, không cần cài thêm." },
  { id: 672, category: "Node.js", subcategory: "Express", level: "beginner", q: "Express.js là gì? Tại sao phổ biến trong Node.js ecosystem?", a: "Express là web framework minimal và flexible cho Node.js. Phổ biến vì: API đơn giản, middleware system mạnh mẽ, routing linh hoạt, ecosystem plugins khổng lồ, ít opinionated. Là nền tảng của nhiều framework khác như NestJS, LoopBack." },
  { id: 673, category: "Node.js", subcategory: "Express", level: "beginner", q: "Middleware trong Express là gì? Cách hoạt động?", a: "Middleware là function có signature `(req, res, next)`. Được thực thi tuần tự theo thứ tự đăng ký. Mỗi middleware có thể: modify req/res, kết thúc request-response cycle, hoặc gọi `next()` để chuyển tiếp middleware tiếp theo. Ví dụ: logging, authentication, body parsing." },
  { id: 674, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Router trong Express là gì? Cách tổ chức routes?", a: "express.Router() tạo mini-app với routes và middleware riêng biệt. Dùng để tổ chức code theo feature/resource (userRouter, productRouter). Mount router vào app với `app.use('/api/users', userRouter)`. Giúp code modular và dễ maintain." },
  { id: 675, category: "Node.js", subcategory: "Express", level: "intermediate", q: "REST API trong Express: cách định nghĩa các HTTP methods?", a: "Express hỗ trợ tất cả HTTP methods: `app.get()`, `app.post()`, `app.put()`, `app.patch()`, `app.delete()`. Route parameters dùng `:param` (`/users/:id`). Query strings qua `req.query`. Request body qua `req.body` (cần `express.json()` middleware)." },
  { id: 676, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Error handling middleware trong Express hoạt động như thế nào?", a: "Error handling middleware có 4 tham số: `(err, req, res, next)`. Phải đăng ký sau tất cả routes và middleware khác. Khi gọi `next(error)` hoặc `next(new Error())`, Express bỏ qua non-error middleware và truyền đến error handler đầu tiên." },
  { id: 677, category: "Node.js", subcategory: "Express", level: "intermediate", q: "CORS trong Express: cách cấu hình cho phép cross-origin requests?", a: "Dùng package `cors`: `app.use(cors())` cho phép tất cả origins (không khuyến nghị production). Cấu hình chi tiết: `cors({ origin: 'https://example.com', methods: ['GET','POST'], credentials: true })`. Hoặc tự implement middleware set Access-Control headers thủ công." },
  { id: 678, category: "Node.js", subcategory: "Express", level: "intermediate", q: "express.json() và express.urlencoded() middleware dùng để làm gì?", a: "express.json() parse request body với Content-Type application/json thành `req.body` object. express.urlencoded({ extended: true }) parse form data (application/x-www-form-urlencoded). Cả hai là built-in middleware của Express 4.16+, không cần cài `body-parser` riêng." },
  { id: 679, category: "Node.js", subcategory: "Express", level: "intermediate", q: "Rate limiting trong Express là gì? Cách implement?", a: "Rate limiting giới hạn số requests từ một IP trong khoảng thời gian nhất định, bảo vệ API khỏi spam và DDoS. Dùng package `express-rate-limit`: `rateLimit({ windowMs: 15*60*1000, max: 100 })` giới hạn 100 requests/15 phút per IP." },
  { id: 680, category: "Node.js", subcategory: "Express", level: "advanced", q: "Sự khác biệt giữa Express 4 và Express 5 là gì?", a: "Express 5 (stable 2024): async error handling tự động (throw trong async route tự chuyển đến error handler, không cần try/catch), path matching cải tiến, một số breaking changes về routing syntax. Express 4 yêu cầu wrap async routes với try/catch hoặc dùng `express-async-handler`." },

  // === NODE.JS: Advanced (681-700) ===
  { id: 681, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "JWT (JSON Web Token) là gì? Cấu trúc của JWT?", a: "JWT là chuẩn mở để truyền thông tin an toàn giữa các bên dưới dạng JSON. Gồm 3 phần mã hóa base64 ngăn bởi dấu chấm: Header (algorithm), Payload (claims/data), Signature (verify tính toàn vẹn). Thường dùng cho stateless authentication." },
  { id: 682, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "Cách implement JWT authentication trong Express API?", a: "Khi login thành công, tạo JWT với `jwt.sign(payload, secret, {expiresIn})`. Client lưu token và gửi trong Authorization header: `Bearer <token>`. Middleware verify: `jwt.verify(token, secret)` trả về payload nếu hợp lệ, throw error nếu không hợp lệ hoặc expired." },
  { id: 683, category: "Node.js", subcategory: "Authentication", level: "intermediate", q: "bcrypt là gì? Cách dùng để hash password?", a: "bcrypt là hàm hash một chiều được thiết kế đặc biệt cho password, có built-in salt và work factor (cost). Dùng `bcrypt.hash(password, saltRounds)` để hash, `bcrypt.compare(password, hash)` để verify. saltRounds thường là 10-12, tăng thì an toàn hơn nhưng chậm hơn." },
  { id: 684, category: "Node.js", subcategory: "Authentication", level: "advanced", q: "Access token và Refresh token khác nhau như thế nào?", a: "Access token: short-lived (15 phút - 1 giờ), gửi trong mỗi request để authenticate. Refresh token: long-lived (7-30 ngày), chỉ dùng để lấy access token mới, lưu an toàn hơn (HttpOnly cookie). Khi access token hết hạn, dùng refresh token để lấy cặp tokens mới mà không cần đăng nhập lại." },
  { id: 685, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Clustering trong Node.js là gì? Tại sao cần thiết?", a: "Node.js single-threaded chỉ dùng một CPU core. Cluster module cho phép tạo nhiều worker processes, mỗi process chạy trên một core riêng. Master process phân phối connections cho workers qua round-robin (Linux) hoặc OS scheduling (Windows). Maximizes multi-core CPU utilization." },
  { id: 686, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Worker Threads trong Node.js là gì? Khác gì với Cluster?", a: "Worker Threads chạy JavaScript trong separate threads, chia sẻ memory qua SharedArrayBuffer. Cluster tạo separate processes, không chia sẻ memory. Worker Threads phù hợp cho CPU-intensive tasks (image processing, encryption). Cluster phù hợp để scale HTTP server trên multiple cores." },
  { id: 687, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Microservices architecture với Node.js: ưu và nhược điểm?", a: "Ưu điểm: scale từng service độc lập, deploy riêng lẻ, fault isolation, tự do chọn technology. Nhược điểm: complexity tăng (network calls thay vì function calls), cần service discovery, distributed tracing, data consistency khó hơn. Phù hợp team lớn, app phức tạp." },
  { id: 688, category: "Node.js", subcategory: "Caching", level: "intermediate", q: "Caching trong Node.js API: các chiến lược phổ biến?", a: "In-memory cache: `node-cache` hoặc Map (single server, lost on restart). Redis: distributed cache, persistent, dùng `ioredis` hoặc `@upstash/redis`. HTTP caching: Cache-Control headers. CDN caching: static assets. Cache-aside pattern: check cache trước, miss thì fetch từ DB và cache." },
  { id: 689, category: "Node.js", subcategory: "Error Handling", level: "intermediate", q: "Cách xử lý unhandled Promise rejections trong Node.js?", a: "Từ Node.js 15+, unhandled rejection mặc định crash process. Xử lý bằng: `process.on('unhandledRejection', (reason, promise) => {...})` để log và gracefully shutdown. Best practice: luôn có `.catch()` hoặc try/catch cho mọi async operation. Dùng monitoring để alert khi có unhandled errors." },
  { id: 690, category: "Node.js", subcategory: "File System", level: "intermediate", q: "fs module trong Node.js: fs.readFile vs fs.createReadStream khác nhau như thế nào?", a: "fs.readFile() đọc toàn bộ file vào memory trước khi callback. Phù hợp file nhỏ. fs.createReadStream() đọc file theo chunks, phù hợp file lớn (ít memory usage). Khi stream file lớn đến HTTP response, dùng createReadStream().pipe(res) để tránh out-of-memory." },
  { id: 691, category: "Node.js", subcategory: "File System", level: "intermediate", q: "Sự khác biệt giữa fs.readFile và fs.readFileSync là gì?", a: "fs.readFileSync() là blocking - block event loop cho đến khi file được đọc xong. fs.readFile() là non-blocking - đọc async và gọi callback khi xong. Trong server code, luôn dùng async version để không block event loop. readFileSync chỉ hợp lý trong startup/initialization." },
  { id: 692, category: "Node.js", subcategory: "Environment", level: "beginner", q: "Environment variables trong Node.js: cách dùng và tại sao quan trọng?", a: "Biến môi trường (process.env) lưu cấu hình nhạy cảm bên ngoài code như API keys, database URLs, port numbers. Dùng file `.env` với package `dotenv` để load khi development, inject trực tiếp trong production. KHÔNG commit file .env vào git. Giúp tách biệt config khỏi code." },
  { id: 693, category: "Node.js", subcategory: "Performance", level: "advanced", q: "Event loop blocking trong Node.js là gì? Làm thế nào để tránh?", a: "Blocking xảy ra khi synchronous heavy computation chạy lâu (vòng lặp tính toán, regex phức tạp), ngăn event loop xử lý requests khác. Giải pháp: chia nhỏ task với setImmediate(), offload sang Worker Threads, hoặc dùng microservices. `clinic.js` giúp phát hiện blocking." },
  { id: 694, category: "Node.js", subcategory: "Streams", level: "advanced", q: "Backpressure trong Node.js streams là gì? Tại sao quan trọng?", a: "Backpressure xảy ra khi Writable stream không xử lý kịp data từ Readable. Nếu không xử lý, memory sẽ tràn. Cơ chế: khi `write()` trả về false, dừng đọc từ Readable. Khi Writable emit 'drain', tiếp tục đọc. `pipe()` tự động xử lý backpressure." },
  { id: 695, category: "Node.js", subcategory: "Debugging", level: "intermediate", q: "Cách debug Node.js application?", a: "Các cách: (1) `node --inspect app.js` mở Chrome DevTools debugger, (2) VS Code built-in debugger với launch.json, (3) console.log (đơn giản nhưng hiệu quả), (4) `debug` package với namespaced logging, (5) `clinic.js` và `0x` cho performance profiling." },
  { id: 696, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Event Emitter trong Node.js là gì? Cách dùng?", a: "EventEmitter là class built-in cho phép implement publish-subscribe pattern. Dùng `.on(event, listener)` đăng ký listener, `.emit(event, ...args)` phát event. Nhiều Node.js APIs kế thừa EventEmitter (streams, http.Server). Custom class extend EventEmitter để thêm event-based communication." },
  { id: 697, category: "Node.js", subcategory: "Security", level: "intermediate", q: "Các lỗ hổng bảo mật phổ biến trong Node.js API và cách phòng tránh?", a: "SQL/NoSQL injection: dùng parameterized queries/ORM. XSS: sanitize input, escape output. ReDoS (regex denial of service): tránh regex phức tạp với user input. Directory traversal: validate file paths. npm audit: kiểm tra vulnerabilities trong dependencies. Helmet.js: set security HTTP headers." },
  { id: 698, category: "Node.js", subcategory: "Architecture", level: "advanced", q: "Graceful shutdown trong Node.js là gì? Tại sao quan trọng?", a: "Graceful shutdown: khi nhận signal SIGTERM, dừng nhận requests mới, chờ requests hiện tại hoàn thành, đóng DB connections và cleanup trước khi exit. Quan trọng để không mất data và không return lỗi cho clients đang request. Dùng với Docker/Kubernetes để zero-downtime deployments." },
  { id: 699, category: "Node.js", subcategory: "Testing", level: "intermediate", q: "Cách viết unit tests cho Node.js API với Jest?", a: "Dùng Jest với `supertest` để test HTTP endpoints mà không cần start server thật. Mock dependencies với `jest.mock()`. Test isolated units (functions, middleware). Integration tests dùng test database. Coverage với `jest --coverage`. CI/CD chạy tests tự động khi push code." },
  { id: 700, category: "Node.js", subcategory: "Performance", level: "advanced", q: "PM2 là gì? Tại sao dùng PM2 trong production?", a: "PM2 là process manager cho Node.js production. Tính năng: auto-restart khi crash, cluster mode dùng tất cả CPU cores, zero-downtime reloads, logging, monitoring, startup scripts. Dùng `pm2 start app.js -i max` để chạy cluster mode với số workers = số CPU cores." },

  // === DATABASE: SQL Cơ Bản (701-715) ===
  { id: 701, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "SQL là gì? Các loại SQL commands chính?", a: "SQL (Structured Query Language) là ngôn ngữ truy vấn cơ sở dữ liệu quan hệ. Phân loại: DDL (Data Definition Language: CREATE, ALTER, DROP), DML (Data Manipulation: SELECT, INSERT, UPDATE, DELETE), DCL (Data Control: GRANT, REVOKE), TCL (Transaction Control: COMMIT, ROLLBACK)." },
  { id: 702, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "Câu lệnh SELECT cơ bản trong SQL như thế nào?", a: "Cú pháp: `SELECT columns FROM table WHERE condition ORDER BY col ASC/DESC LIMIT n`. Ví dụ: `SELECT name, email FROM users WHERE active = true ORDER BY created_at DESC LIMIT 10`. SELECT * lấy tất cả columns nhưng không nên dùng trong production vì lấy data không cần thiết." },
  { id: 703, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "INSERT, UPDATE, DELETE trong SQL hoạt động như thế nào?", a: "INSERT: `INSERT INTO users (name, email) VALUES ('Dinh', 'dinh@test.com')`. UPDATE: `UPDATE users SET name = 'New' WHERE id = 1` (luôn có WHERE để tránh update toàn bộ). DELETE: `DELETE FROM users WHERE id = 1` (luôn có WHERE clause)." },
  { id: 704, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Các loại JOIN trong SQL: INNER JOIN, LEFT JOIN, RIGHT JOIN, FULL OUTER JOIN khác nhau như thế nào?", a: "INNER JOIN: chỉ trả về rows có match ở cả hai bảng. LEFT JOIN: tất cả rows từ bảng trái, NULL nếu không match bảng phải. RIGHT JOIN: ngược lại. FULL OUTER JOIN: tất cả rows từ cả hai bảng, NULL khi không match. CROSS JOIN: tất cả combinations (Cartesian product)." },
  { id: 705, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "WHERE và HAVING trong SQL khác nhau như thế nào?", a: "WHERE lọc rows trước khi GROUP BY, không dùng được aggregate functions. HAVING lọc groups sau GROUP BY, có thể dùng aggregate functions (COUNT, SUM, AVG). Ví dụ: `SELECT dept, COUNT(*) FROM employees WHERE active = true GROUP BY dept HAVING COUNT(*) > 5`." },
  { id: 706, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "GROUP BY trong SQL dùng để làm gì? Cho ví dụ?", a: "GROUP BY nhóm rows có cùng giá trị ở columns chỉ định, dùng với aggregate functions. Ví dụ: `SELECT category, COUNT(*) as total, AVG(price) as avg_price FROM products GROUP BY category`. Mỗi group trả về một row trong kết quả." },
  { id: 707, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Aggregate functions trong SQL là gì? Các hàm phổ biến?", a: "Aggregate functions tính toán từ nhiều rows và trả về một giá trị. Phổ biến: COUNT() đếm rows, SUM() tổng, AVG() trung bình, MAX() giá trị lớn nhất, MIN() giá trị nhỏ nhất. Thường dùng với GROUP BY. COUNT(*) đếm tất cả rows, COUNT(col) bỏ qua NULLs." },
  { id: 708, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Index trong SQL là gì? Tại sao cần thiết?", a: "Index là cấu trúc dữ liệu (B-tree) giúp database tìm kiếm nhanh hơn mà không cần full table scan. Tăng tốc độ SELECT nhưng làm chậm INSERT/UPDATE/DELETE (phải cập nhật index). Nên index: columns trong WHERE, JOIN, ORDER BY. Không nên index bảng nhỏ hoặc columns ít unique values." },
  { id: 709, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "Subquery trong SQL là gì? Khi nào dùng subquery vs JOIN?", a: "Subquery là query lồng bên trong query khác. Correlated subquery tham chiếu outer query. JOIN thường hiệu quả hơn subquery vì optimizer có thể optimize tốt hơn. Subquery phù hợp khi: cần IN/NOT IN với list, EXISTS checks, hoặc khi JOIN tạo ra duplicate rows." },
  { id: 710, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "Window functions trong SQL là gì? Ví dụ về ROW_NUMBER, RANK?", a: "Window functions tính toán dựa trên window (tập rows liên quan) mà không collapse rows như GROUP BY. Ví dụ: `ROW_NUMBER() OVER (PARTITION BY dept ORDER BY salary DESC)` đánh số thứ tự trong mỗi department. RANK cho phép ties, DENSE_RANK không bỏ số." },
  { id: 711, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "EXPLAIN và EXPLAIN ANALYZE trong PostgreSQL dùng để làm gì?", a: "EXPLAIN cho thấy execution plan của query (cách database dự định thực thi). EXPLAIN ANALYZE thực sự chạy query và so sánh estimated vs actual rows. Dùng để tìm slow queries, xem index có được dùng không (Index Scan vs Seq Scan), và optimize query performance." },
  { id: 712, category: "Database", subcategory: "SQL Cơ Bản", level: "beginner", q: "NULL trong SQL là gì? Cách kiểm tra NULL?", a: "NULL đại diện cho giá trị không xác định/missing, khác với 0 hoặc empty string. Kiểm tra bằng `IS NULL` / `IS NOT NULL`, KHÔNG dùng `= NULL`. Aggregate functions (trừ COUNT(*)) bỏ qua NULL. NULL trong arithmetic operation trả về NULL. Dùng COALESCE(col, default) để xử lý NULL." },
  { id: 713, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "UNION và UNION ALL trong SQL khác nhau như thế nào?", a: "UNION kết hợp kết quả của hai SELECT và loại bỏ duplicate rows (có overhead sorting). UNION ALL kết hợp và giữ tất cả rows kể cả duplicates, nhanh hơn. Cả hai yêu cầu cùng số columns và compatible data types. Dùng UNION ALL khi biết không có duplicates hoặc cần duplicates." },
  { id: 714, category: "Database", subcategory: "SQL Cơ Bản", level: "intermediate", q: "CTEs (Common Table Expressions) trong SQL là gì? Lợi ích?", a: "CTE là named temporary result set định nghĩa bằng WITH clause, có thể reference trong query chính. Lợi ích: dễ đọc hơn subquery, có thể reference nhiều lần, hỗ trợ recursive queries (cho hierarchical data như org chart, category tree). `WITH RECURSIVE` xử lý self-referential data." },
  { id: 715, category: "Database", subcategory: "SQL Cơ Bản", level: "advanced", q: "Composite index là gì? Column ordering trong index quan trọng như thế nào?", a: "Composite index là index trên nhiều columns. Column ordering cực kỳ quan trọng: index (a, b, c) có thể dùng cho queries filter trên (a), (a,b), (a,b,c) nhưng KHÔNG cho (b) hoặc (c) alone (leftmost prefix rule). Đặt columns có highest cardinality hoặc xuất hiện nhiều nhất trong WHERE đầu tiên." },

  // === DATABASE: Database Design (716-725) ===
  { id: 716, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Normalization trong database là gì? Tại sao quan trọng?", a: "Normalization là quá trình tổ chức database để giảm redundancy và improve data integrity. Các normal forms: 1NF (atomic values), 2NF (full functional dependency), 3NF (no transitive dependency). Giảm data duplication, update anomalies, và storage. Nhưng denormalization đôi khi cần cho performance." },
  { id: 717, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Primary key và Foreign key là gì? Vai trò trong database?", a: "Primary key: column (hoặc combination) uniquely identifies mỗi row trong bảng, không NULL, không trùng. Foreign key: column tham chiếu primary key của bảng khác, đảm bảo referential integrity (không thể insert FK value không tồn tại trong bảng referenced). Quan trọng cho JOIN operations." },
  { id: 718, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Các loại relationships trong database design là gì?", a: "One-to-One: mỗi record A có đúng một record B (ví dụ user và user_profile). One-to-Many: một record A có nhiều records B (ví dụ user và posts). Many-to-Many: nhiều A liên kết nhiều B, cần junction/bridge table (ví dụ students và courses thông qua enrollments)." },
  { id: 719, category: "Database", subcategory: "Database Design", level: "intermediate", q: "ER Diagram (Entity-Relationship Diagram) là gì? Các thành phần chính?", a: "ER Diagram là công cụ trực quan hóa database schema. Thành phần: Entities (bảng, hình chữ nhật), Attributes (columns, hình oval), Relationships (liên kết, hình thoi), Cardinality (1:1, 1:N, M:N). Dùng để thiết kế database trước khi implement, dễ communicate với stakeholders." },
  { id: 720, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Cascade trong foreign key constraint là gì? ON DELETE CASCADE hoạt động thế nào?", a: "Cascade tự động propagate action từ parent table sang child table. ON DELETE CASCADE: xóa parent row thì tự động xóa tất cả related child rows. ON UPDATE CASCADE: update primary key thì tự update foreign key. Cần cẩn thận vì có thể xóa data hàng loạt không mong muốn." },
  { id: 721, category: "Database", subcategory: "Database Design", level: "advanced", q: "Denormalization là gì? Khi nào nên denormalize database?", a: "Denormalization là cố ý thêm redundant data để tăng query performance. Nên denormalize khi: read-heavy workload với complex JOINs chậm, reporting/analytics queries, hoặc sau khi normalize và profiling cho thấy performance vấn đề. Trade-off: faster reads vs slower writes và storage overhead." },
  { id: 722, category: "Database", subcategory: "Database Design", level: "intermediate", q: "Surrogate key và Natural key khác nhau như thế nào?", a: "Natural key: dữ liệu thực có business meaning (SSN, email, ISBN). Surrogate key: ID nhân tạo không có business meaning (auto-increment integer, UUID). Surrogate key thường được ưa chuộng vì: stable (không thay đổi khi business data thay đổi), hiệu quả cho JOINs, simple." },
  { id: 723, category: "Database", subcategory: "Database Design", level: "advanced", q: "Soft delete là gì? Ưu và nhược điểm so với hard delete?", a: "Soft delete: thêm column `deleted_at` hoặc `is_deleted`, không xóa record thật sự. Ưu: có thể khôi phục, audit trail, tránh cascade delete issues. Nhược: queries phức tạp hơn (WHERE deleted_at IS NULL), database phình to, cần cẩn thận không query deleted records." },
  { id: 724, category: "Database", subcategory: "Database Design", level: "intermediate", q: "UUID vs Auto-increment ID: khi nào nên dùng loại nào?", a: "Auto-increment: đơn giản, nhỏ gọn (4/8 bytes), dễ debug. UUID: globally unique không cần central coordination, phù hợp distributed systems và microservices, khó đoán (security). Nhược điểm UUID: lớn hơn (16 bytes), index fragmentation, khó đọc. UUID v7 có timestamp prefix, tốt hơn cho indexing." },
  { id: 725, category: "Database", subcategory: "Database Design", level: "advanced", q: "Database migration là gì? Tại sao quan trọng trong CI/CD?", a: "Database migration là scripts thay đổi database schema một cách có kiểm soát và versioned. Mỗi migration có up (apply) và down (rollback). Quan trọng trong CI/CD: đảm bảo schema thay đổi đồng bộ với code changes, có thể rollback khi deploy lỗi, team làm việc trên cùng schema version." },

  // === DATABASE: NoSQL & ORM (726-740) ===
  { id: 726, category: "Database", subcategory: "NoSQL", level: "beginner", q: "NoSQL là gì? Các loại NoSQL databases phổ biến?", a: "NoSQL là databases không dùng relational model truyền thống. Bốn loại chính: Document stores (MongoDB, CouchDB), Key-Value stores (Redis, DynamoDB), Column-family stores (Cassandra, HBase), Graph databases (Neo4j). Phù hợp cho unstructured data, horizontal scaling, và flexible schema." },
  { id: 727, category: "Database", subcategory: "NoSQL", level: "beginner", q: "MongoDB là gì? Document-based database hoạt động như thế nào?", a: "MongoDB lưu data dưới dạng BSON documents (JSON-like). Mỗi document có thể có schema khác nhau trong cùng collection (flexible schema). Thay vì tables, MongoDB dùng collections. Thay vì rows, dùng documents. Hỗ trợ nested documents và arrays." },
  { id: 728, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "So sánh MongoDB và PostgreSQL: khi nào chọn cái nào?", a: "Chọn PostgreSQL khi: data có quan hệ rõ ràng, cần ACID transactions, schema cố định, complex queries với JOINs. Chọn MongoDB khi: data có cấu trúc variable/nested, cần flexible schema, horizontal scaling quan trọng, document-centric data (content, catalog, user profiles)." },
  { id: 729, category: "Database", subcategory: "ORM", level: "intermediate", q: "ORM (Object-Relational Mapper) là gì? Lợi ích và nhược điểm?", a: "ORM là layer ánh xạ database tables thành objects trong code, cho phép thao tác database bằng programming language thay vì SQL. Lợi ích: type-safety, migrations, code reuse, database abstraction. Nhược điểm: overhead, khó optimize complex queries, N+1 query problem, abstraction leaks." },
  { id: 730, category: "Database", subcategory: "ORM", level: "intermediate", q: "Prisma ORM là gì? Tại sao phổ biến trong Node.js/TypeScript ecosystem?", a: "Prisma là ORM thế hệ mới cho Node.js/TypeScript với schema-first approach. Điểm mạnh: type-safe database client (auto-generated từ schema), Prisma Migrate cho migrations, Prisma Studio (GUI), excellent TypeScript support. So với Sequelize/TypeORM, Prisma có DX tốt hơn và type safety mạnh hơn." },
  { id: 731, category: "Database", subcategory: "ORM", level: "intermediate", q: "Prisma schema file hoạt động như thế nào?", a: "schema.prisma là single source of truth, định nghĩa data models với types và relations. Prisma generate TypeScript client từ schema. `prisma migrate dev` tạo SQL migration từ schema changes. `prisma generate` regenerate client. Models map to database tables." },
  { id: 732, category: "Database", subcategory: "ORM", level: "intermediate", q: "N+1 query problem trong ORM là gì? Cách giải quyết trong Prisma?", a: "N+1 problem: query 1 lần lấy list (1 query), rồi loop qua từng item để fetch related data (N queries). Trong Prisma, giải quyết bằng `include` để eager load relations: `prisma.user.findMany({ include: { posts: true } })`. Tránh dùng lazy loading trong loops." },
  { id: 733, category: "Database", subcategory: "ORM", level: "intermediate", q: "Sequelize là gì? So sánh với Prisma?", a: "Sequelize là ORM lâu đời cho Node.js, hỗ trợ MySQL, PostgreSQL, SQLite, MSSQL. Dùng class-based models, decorator support, phong phú tính năng. So với Prisma: Sequelize linh hoạt hơn nhưng TypeScript support yếu hơn, verbose hơn, DX kém hơn. Prisma là lựa chọn mới hơn cho TypeScript projects." },
  { id: 734, category: "Database", subcategory: "ORM", level: "intermediate", q: "Mongoose là gì? Schema trong Mongoose hoạt động như thế nào?", a: "Mongoose là ODM (Object Document Mapper) cho MongoDB trong Node.js. Schema định nghĩa structure, types, validation, và defaults cho documents. Model là class compiled từ Schema. Middleware (pre/post hooks) cho validation và business logic. Phổ biến nhất khi dùng MongoDB với Node.js." },
  { id: 735, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Redis là gì? Use cases phổ biến của Redis?", a: "Redis là in-memory data store với persistence tùy chọn, hỗ trợ nhiều data structures (strings, hashes, lists, sets, sorted sets). Use cases: caching, session storage, pub/sub messaging, rate limiting, leaderboards, job queues. Cực nhanh vì all in-memory, latency microseconds." },
  { id: 736, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Khi nào nên dùng Redis làm cache?", a: "Dùng Redis cache khi: data đọc nhiều hơn ghi, computation expensive (complex DB queries), cần reduce database load, data có thể stale một lúc. Chiến lược: Cache-aside (check cache trước), Write-through (write cache + DB đồng thời), Write-behind (write cache, async write DB). Set TTL phù hợp." },
  { id: 737, category: "Database", subcategory: "NoSQL", level: "advanced", q: "MongoDB aggregation pipeline là gì?", a: "Aggregation pipeline là series of stages để transform và compute data trong MongoDB. Stages phổ biến: $match (filter), $group (group và aggregate), $project (reshape documents), $sort, $limit, $lookup (JOIN). Mạnh hơn MapReduce, là công cụ chính để analytics và reporting trong MongoDB." },
  { id: 738, category: "Database", subcategory: "ORM", level: "advanced", q: "Database transactions trong Prisma: cách sử dụng?", a: "Prisma hỗ trợ hai loại transactions: Sequential transactions với `prisma.$transaction([op1, op2])` chạy tuần tự, rollback nếu bất kỳ operation nào fail. Interactive transactions với `prisma.$transaction(async (tx) => {...})` cho phép conditional logic và sử dụng tx client thay cho prisma client." },
  { id: 739, category: "Database", subcategory: "ORM", level: "intermediate", q: "Drizzle ORM là gì? So sánh với Prisma?", a: "Drizzle là TypeScript ORM nhẹ, type-safe, SQL-first. Viết queries gần với SQL thuần nhưng có TypeScript types. Nhanh hơn Prisma vì ít overhead hơn, không cần Prisma engine binary. Schema định nghĩa bằng TypeScript. Phổ biến với Next.js và edge environments. Prisma có DX tốt hơn nhưng Drizzle nhẹ hơn." },
  { id: 740, category: "Database", subcategory: "NoSQL", level: "intermediate", q: "Document embedding vs referencing trong MongoDB: khi nào dùng cái nào?", a: "Embedding (nested document): dùng khi data được truy cập cùng nhau thường xuyên, quan hệ 1:1 hoặc 1:few, data ít thay đổi. Referencing (separate documents với ObjectId): dùng khi data lớn, quan hệ many-to-many, data được truy cập độc lập, cần update riêng biệt." },

  // === DATABASE: Advanced (741-750) ===
  { id: 741, category: "Database", subcategory: "Advanced", level: "advanced", q: "ACID properties trong database là gì?", a: "ACID đảm bảo database transactions đáng tin cậy: Atomicity (transaction hoặc thành công toàn bộ hoặc rollback toàn bộ), Consistency (data luôn ở trạng thái hợp lệ), Isolation (transactions không ảnh hưởng lẫn nhau khi chạy đồng thời), Durability (committed data không mất dù system crash)." },
  { id: 742, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database transactions là gì? Cách sử dụng trong SQL?", a: "Transaction là nhóm operations thực hiện như một đơn vị atomic. Cú pháp: `BEGIN; ... COMMIT;` hoặc `BEGIN; ... ROLLBACK;`. Dùng khi cần nhiều operations phải cùng thành công hoặc cùng fail (ví dụ chuyển tiền: trừ account A, cộng account B phải là một transaction)." },
  { id: 743, category: "Database", subcategory: "Advanced", level: "advanced", q: "Transaction isolation levels là gì? Các levels là gì?", a: "Isolation levels kiểm soát visibility giữa concurrent transactions. Từ thấp đến cao: READ UNCOMMITTED (dirty reads), READ COMMITTED (default PostgreSQL), REPEATABLE READ (default MySQL), SERIALIZABLE (highest, no anomalies). Isolation cao hơn thì an toàn hơn nhưng concurrency thấp hơn và latency cao hơn." },
  { id: 744, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database indexing strategies: B-tree index, Hash index, GIN index khác nhau như thế nào?", a: "B-tree: default, phù hợp range queries và equality, sortable. Hash: chỉ equality checks, nhanh hơn B-tree cho equality nhưng không dùng được cho range. GIN (Generalized Inverted Index): phù hợp full-text search, arrays, JSONB. GiST: geometric data và full-text. Chọn index type dựa trên query patterns." },
  { id: 745, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database replication là gì? Primary-replica architecture hoạt động như thế nào?", a: "Replication copy data từ primary (master) database sang một hoặc nhiều replicas (slaves). Primary xử lý writes, replicas xử lý reads - giúp scale read throughput. Replication có thể synchronous (confirm sau khi replica nhận) hoặc asynchronous (confirm ngay, replica lag). Replicas cũng dùng làm failover." },
  { id: 746, category: "Database", subcategory: "Advanced", level: "advanced", q: "Database sharding là gì? Khi nào cần sharding?", a: "Sharding là chia data ngang (horizontal partitioning) ra nhiều database servers, mỗi shard chứa một tập con data. Cần khi dataset quá lớn cho một server. Sharding strategies: range-based, hash-based, directory-based. Nhược điểm: complexity tăng, cross-shard queries khó, re-sharding tốn kém." },
  { id: 747, category: "Database", subcategory: "Advanced", level: "advanced", q: "CAP theorem là gì? Ý nghĩa trong database selection?", a: "CAP theorem: trong distributed database, chỉ có thể đảm bảo tối đa 2 trong 3 properties: Consistency (mọi node thấy data giống nhau), Availability (mọi request nhận response), Partition Tolerance (hoạt động khi network partition). Thực tế P luôn cần, nên chọn CP hoặc AP. MongoDB tùy cấu hình: default gần AP, với writeConcern/readConcern majority → CP. Cassandra thiên AP." },
  { id: 748, category: "Database", subcategory: "Advanced", level: "advanced", q: "Connection pooling trong database là gì? Tại sao quan trọng?", a: "Connection pooling duy trì pool of reusable database connections thay vì tạo connection mới cho mỗi request. Tạo connection tốn thời gian (TCP handshake, auth). Pool giới hạn max connections, tránh overwhelm database. Cấu hình pool size phụ thuộc vào database limits và concurrency requirements." },
  { id: 749, category: "Database", subcategory: "Advanced", level: "advanced", q: "Full-text search trong database là gì? PostgreSQL vs Elasticsearch?", a: "Full-text search tìm kiếm trong text content, hỗ trợ stemming, ranking theo relevance. PostgreSQL tích hợp full-text search với tsvector/tsquery, đủ cho moderate needs. Elasticsearch chuyên dụng hơn: distributed, horizontal scaling, advanced relevance scoring, rich query DSL. Dùng Elasticsearch khi search là core feature." },
  { id: 750, category: "Database", subcategory: "Advanced", level: "advanced", q: "Optimistic locking vs Pessimistic locking trong database là gì?", a: "Pessimistic locking: lock record khi đọc, ngăn others modify cho đến khi unlock (SELECT FOR UPDATE). An toàn nhưng giảm concurrency. Optimistic locking: không lock, kiểm tra version/timestamp khi update - nếu thay đổi thì reject và retry. Phù hợp read-heavy, low contention scenarios." },

  // === BUILD TOOLS (751-765) ===
  { id: 751, category: "Build Tools", subcategory: "Webpack", level: "intermediate", q: "Webpack là gì? Vai trò trong modern web development?", a: "Webpack là module bundler tổng hợp tất cả assets (JS, CSS, images) thành bundle files tối ưu. Tính năng: code splitting, tree shaking, hot module replacement, loaders để process các file types. Là foundation của nhiều tools (Create React App, Vue CLI) nhưng config phức tạp." },
  { id: 752, category: "Build Tools", subcategory: "Webpack", level: "intermediate", q: "Loaders và Plugins trong Webpack khác nhau như thế nào?", a: "Loaders transform file types thành modules (babel-loader chuyển JS, css-loader xử lý CSS, file-loader xử lý images). Loaders hoạt động ở file level. Plugins can thiệp vào build process rộng hơn: HtmlWebpackPlugin tạo HTML, MiniCssExtractPlugin tách CSS, TerserPlugin minify JS." },
  { id: 753, category: "Build Tools", subcategory: "Vite", level: "beginner", q: "Vite là gì? Tại sao nhanh hơn Webpack trong development?", a: "Vite là build tool thế hệ mới của Evan You (tác giả Vue). Trong development: dùng native ES modules trong browser, không bundle - chỉ transform file khi requested. HMR cực nhanh. Production: dùng Rollup để bundle. Nhanh hơn Webpack vì không bundle toàn bộ trong dev mode." },
  { id: 754, category: "Build Tools", subcategory: "Vite", level: "intermediate", q: "Sự khác biệt giữa Vite dev server và Webpack dev server?", a: "Webpack dev server bundle toàn bộ app khi start, chậm hơn với project lớn. Vite dùng esbuild để pre-bundle dependencies một lần, serve source files qua native ESM. HMR của Vite update chỉ module thay đổi, không re-bundle toàn bộ. Start time Vite thường dưới 1 giây vs vài giây với Webpack." },
  { id: 755, category: "Build Tools", subcategory: "Babel", level: "intermediate", q: "Babel là gì? Vai trò trong JavaScript toolchain?", a: "Babel là JavaScript transpiler chuyển modern JavaScript (ES6+, JSX, TypeScript) thành code tương thích trình duyệt cũ. Cấu hình qua `.babelrc` hoặc `babel.config.js`. Plugins xử lý từng syntax feature. Presets là collection của plugins (preset-env, preset-react, preset-typescript)." },
  { id: 756, category: "Build Tools", subcategory: "SWC", level: "intermediate", q: "SWC là gì? So sánh với Babel?", a: "SWC (Speedy Web Compiler) là Babel alternative viết bằng Rust, nhanh hơn 20-70x. Hỗ trợ cùng tính năng: transpile modern JS, JSX, TypeScript. Được dùng trong Next.js (thay Babel), Vite plugin, Deno. Nhanh hơn nhưng ecosystem plugins nhỏ hơn Babel." },
  { id: 757, category: "Build Tools", subcategory: "Package Managers", level: "beginner", q: "pnpm khác npm và yarn như thế nào?", a: "pnpm dùng content-addressable storage: mỗi package version lưu một lần trên disk, tất cả projects share qua symlinks (tiết kiệm disk). Nhanh hơn npm, strict về dependencies (tránh phantom deps). Yarn có workspaces tốt, PnP mode không cần node_modules. pnpm là lựa chọn ngày càng phổ biến cho monorepos." },
  { id: 758, category: "Build Tools", subcategory: "CI/CD", level: "intermediate", q: "CI/CD là gì? Sự khác biệt giữa CI và CD?", a: "CI (Continuous Integration): tự động build và test code mỗi khi push, phát hiện lỗi sớm. CD (Continuous Delivery): tự động deploy đến staging sau CI thành công. Continuous Deployment: tự động deploy đến production. GitHub Actions, GitLab CI, Jenkins là CI/CD tools phổ biến." },
  { id: 759, category: "Build Tools", subcategory: "CI/CD", level: "intermediate", q: "GitHub Actions là gì? Cấu trúc của một workflow file?", a: "GitHub Actions là CI/CD platform tích hợp trong GitHub. Workflow là YAML file trong `.github/workflows/`. Cấu trúc: `on` (trigger events), `jobs` (các job chạy parallel hoặc sequential), `steps` (các bước trong job sử dụng actions hoặc shell commands). Actions marketplace có hàng nghìn pre-built actions." },
  { id: 760, category: "Build Tools", subcategory: "Docker", level: "intermediate", q: "Docker là gì? Tại sao hữu ích trong development và deployment?", a: "Docker tạo isolated containers chứa app và tất cả dependencies. Đảm bảo 'works on my machine' vì environment giống nhau mọi nơi. Development: tránh dependency conflicts, dễ setup. Production: reproducible builds, easy scaling với Kubernetes, efficient resource usage qua container sharing kernel." },
  { id: 761, category: "Build Tools", subcategory: "Docker", level: "intermediate", q: "Dockerfile là gì? Các instructions cơ bản?", a: "Dockerfile là script định nghĩa cách build Docker image. Instructions cơ bản: `FROM` (base image), `WORKDIR` (set working directory), `COPY`/`ADD` (copy files), `RUN` (execute commands), `ENV` (environment variables), `EXPOSE` (document ports), `CMD`/`ENTRYPOINT` (default command khi start container)." },
  { id: 762, category: "Build Tools", subcategory: "Docker", level: "advanced", q: "Multi-stage builds trong Docker là gì? Lợi ích?", a: "Multi-stage builds dùng nhiều FROM statements để tách build environment khỏi runtime image. Ví dụ: stage 1 dùng node image để build, copy chỉ artifacts cần thiết vào stage 2 với alpine image nhỏ hơn. Giảm đáng kể image size (từ 500MB xuống 50MB), loại bỏ build tools khỏi production image." },
  { id: 763, category: "Build Tools", subcategory: "Monorepo", level: "advanced", q: "Monorepo là gì? Công cụ phổ biến để quản lý monorepo?", a: "Monorepo là single repository chứa nhiều packages/apps. Lợi ích: code sharing dễ dàng, atomic commits across packages, unified tooling. Công cụ: Turborepo (caching, parallel builds), Nx (task orchestration, affected commands), pnpm workspaces (dependency management). Yarn/npm workspaces cũng hỗ trợ monorepo." },
  { id: 764, category: "Build Tools", subcategory: "Webpack", level: "advanced", q: "Tree shaking là gì? Điều kiện để tree shaking hoạt động?", a: "Tree shaking là kỹ thuật loại bỏ dead code (unused exports) khỏi bundle. Điều kiện: phải dùng ES modules (import/export), không CommonJS require. Modules phải side-effect free (hoặc khai báo `sideEffects: false` trong package.json). Webpack và Rollup hỗ trợ tree shaking, giảm bundle size đáng kể." },
  { id: 765, category: "Build Tools", subcategory: "CI/CD", level: "advanced", q: "Blue-Green deployment và Canary deployment là gì?", a: "Blue-Green: duy trì hai production environments (blue=current, green=new). Deploy lên green, test, rồi switch traffic. Rollback instant bằng switch lại blue. Canary: deploy phiên bản mới cho một phần nhỏ users (1-5%), monitor metrics, rồi dần tăng traffic nếu ổn. Giảm risk so với big-bang deployment." },

  // === TESTING (766-780) ===
  { id: 766, category: "Testing", subcategory: "Jest", level: "beginner", q: "Jest là gì? Các tính năng chính của Jest?", a: "Jest là JavaScript testing framework từ Meta, được dùng rộng rãi nhất. Tính năng: zero-config setup, snapshot testing, mocking hệ thống mạnh mẽ, code coverage, watch mode, parallel test execution. Tích hợp tốt với React (Testing Library) và TypeScript." },
  { id: 767, category: "Testing", subcategory: "Jest", level: "beginner", q: "describe, it/test, expect trong Jest được dùng như thế nào?", a: "`describe` nhóm related tests. `it`/`test` định nghĩa test case. `expect` tạo assertion với matchers: `toBe` (strict equality), `toEqual` (deep equality), `toBeTruthy`, `toHaveBeenCalled`, `toThrow`, v.v. `beforeEach`/`afterEach` setup/teardown trước/sau mỗi test." },
  { id: 768, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Mocking trong Jest: jest.fn(), jest.mock(), jest.spyOn() dùng như thế nào?", a: "jest.fn() tạo mock function để track calls và return values. jest.mock('module') mock toàn bộ module (auto-mock hoặc factory). jest.spyOn(obj, 'method') spy on existing method, vẫn gọi implementation gốc trừ khi mockImplementation(). Dùng `mockResolvedValue` cho async mocks." },
  { id: 769, category: "Testing", subcategory: "Vitest", level: "intermediate", q: "Vitest là gì? Tại sao là lựa chọn tốt cho Vite projects?", a: "Vitest là test framework được xây dựng trên Vite, compatible API với Jest. Lợi ích: dùng cùng Vite config và transforms với code, không cần config riêng. Nhanh hơn Jest nhờ Vite's native ESM và esbuild. In-source testing, watch mode thông minh. Là lựa chọn tự nhiên khi project dùng Vite." },
  { id: 770, category: "Testing", subcategory: "Cypress", level: "intermediate", q: "Cypress là gì? Khác gì với Selenium?", a: "Cypress là end-to-end testing framework chạy trong browser (không qua WebDriver). Khác Selenium: chạy trong cùng event loop với app, time-travel debugging với screenshots, automatic waiting (không cần manual waits), real-time reload. Dễ setup và debug hơn. Nhược: chỉ Chromium-based và Firefox, không hỗ trợ multiple tabs." },
  { id: 771, category: "Testing", subcategory: "Playwright", level: "intermediate", q: "Playwright là gì? So sánh với Cypress?", a: "Playwright là E2E testing tool từ Microsoft, hỗ trợ Chromium, Firefox, WebKit (Safari). Khác Cypress: multi-browser support, parallel test execution, multiple tabs/contexts, better mobile emulation, tích hợp tốt với CI. API cũng tương tự nhưng Playwright có network interception mạnh hơn." },
  { id: 772, category: "Testing", subcategory: "TDD/BDD", level: "intermediate", q: "TDD (Test-Driven Development) là gì? Quy trình Red-Green-Refactor?", a: "TDD: viết test trước code. Quy trình: Red (viết test, test fail), Green (viết minimum code để test pass), Refactor (cải thiện code trong khi tests vẫn pass). Lợi ích: code coverage cao, forced modularity, suy nghĩ rõ ràng về requirements, dễ refactor sau." },
  { id: 773, category: "Testing", subcategory: "TDD/BDD", level: "intermediate", q: "BDD (Behavior-Driven Development) là gì? Cú pháp Given-When-Then?", a: "BDD là extension của TDD, focus vào behavior từ user perspective. Dùng ngôn ngữ tự nhiên: Given (context/preconditions), When (action), Then (expected outcome). Giúp collaboration giữa developers và non-technical stakeholders. Cucumber, Jasmine, Jest đều hỗ trợ BDD style." },
  { id: 774, category: "Testing", subcategory: "Test Pyramid", level: "intermediate", q: "Test pyramid là gì? Ba layers của test pyramid?", a: "Test pyramid: nhiều unit tests ở đáy (nhanh, rẻ, isolated), ít integration tests ở giữa (test interaction giữa components), ít E2E tests ở đỉnh (chậm, đắt, brittle). Đảo ngược pyramid (nhiều E2E) tốn kém và chậm. Balance: ~70% unit, ~20% integration, ~10% E2E." },
  { id: 775, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Snapshot testing trong Jest là gì? Khi nào nên dùng?", a: "Snapshot testing serialize output của component/function và so sánh với saved snapshot. Khi output thay đổi, test fail và yêu cầu review. Dùng cho UI components (React Testing Library + toMatchSnapshot), serializable objects. Nên dùng cho stable UI, cập nhật snapshot bằng `jest --updateSnapshot`." },
  { id: 776, category: "Testing", subcategory: "Jest", level: "intermediate", q: "Code coverage là gì? Các loại coverage metrics?", a: "Code coverage đo phần trăm code được chạy bởi tests. Metrics: Statement coverage (% statements executed), Branch coverage (% branches if/else covered), Function coverage (% functions called), Line coverage (% lines executed). 100% coverage không đảm bảo bug-free, nhưng low coverage là red flag." },
  { id: 777, category: "Testing", subcategory: "Testing", level: "intermediate", q: "Integration testing khác unit testing như thế nào?", a: "Unit testing: test một function/class isolated, mock tất cả dependencies. Nhanh, stable, dễ debug. Integration testing: test interaction giữa multiple components/services với real dependencies (database, APIs). Chậm hơn, phát hiện bugs ở boundary. Cả hai đều cần thiết, không thay thế nhau." },
  { id: 778, category: "Testing", subcategory: "Playwright", level: "advanced", q: "Cách xử lý authentication trong Playwright E2E tests?", a: "Playwright hỗ trợ `storageState` để save và reuse authentication state. Login một lần trong globalSetup, save cookie/localStorage với `context.storageState()`. Reuse trong tests bằng `use: { storageState: 'state.json' }`. Page Object Model (POM) pattern tổ chức test code theo pages." },
  { id: 779, category: "Testing", subcategory: "Testing", level: "advanced", q: "Contract testing là gì? Tại sao quan trọng trong microservices?", a: "Contract testing verify API contract (format, structure) giữa service provider và consumer, không cần cả hai chạy đồng thời. Pact là công cụ phổ biến. Consumer viết tests định nghĩa expectations, provider verify. Phát hiện breaking changes sớm trước khi deploy, quan trọng trong microservices environment." },
  { id: 780, category: "Testing", subcategory: "Testing", level: "advanced", q: "Test doubles: mock, stub, spy, fake khác nhau như thế nào?", a: "Stub: trả về hardcoded values, không verify calls. Mock: stub + verify expected calls (jest.fn()). Spy: wrap real implementation, ghi lại calls (jest.spyOn). Fake: simplified working implementation (fake in-memory database). Dummy: placeholder object không thực sự dùng. Martin Fowler phân biệt tất cả trong bài 'Mocks Aren't Stubs'." },

  // === PERFORMANCE (781-790) ===
  { id: 781, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "Core Web Vitals là gì? Ba metrics chính là gì?", a: "Core Web Vitals là bộ metrics của Google đo trải nghiệm người dùng thực tế. Ba metrics: LCP (Largest Contentful Paint - loading performance, target <2.5s), INP (Interaction to Next Paint - thay thế FID từ 3/2024, target <200ms), CLS (Cumulative Layout Shift - visual stability, target <0.1)." },
  { id: 782, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "LCP (Largest Contentful Paint) là gì? Cách cải thiện LCP?", a: "LCP đo thời gian render phần tử lớn nhất trong viewport (thường là hero image hoặc heading). Cải thiện: optimize images (WebP, proper sizing, preload), improve TTFB (server response time), eliminate render-blocking resources, dùng CDN, lazy load images below fold thay vì hero image." },
  { id: 783, category: "Performance", subcategory: "Core Web Vitals", level: "intermediate", q: "CLS (Cumulative Layout Shift) là gì? Nguyên nhân và cách fix?", a: "CLS đo mức độ nội dung trang bị dịch chuyển unexpectedly trong khi loading. Nguyên nhân: images/ads không có dimensions, fonts gây FOUT, dynamically injected content. Fix: luôn set width/height cho images, reserve space cho dynamic content, dùng `font-display: optional` hoặc preload fonts." },
  { id: 784, category: "Performance", subcategory: "Lazy Loading", level: "intermediate", q: "Lazy loading là gì? Cách implement trong React?", a: "Lazy loading trì hoãn loading resources cho đến khi cần thiết. Trong React: `React.lazy()` kết hợp `Suspense` để lazy load components. `next/image` và `next/dynamic` trong Next.js có lazy loading built-in. Images dùng `loading='lazy'` attribute. Giảm initial bundle size và cải thiện Time to Interactive." },
  { id: 785, category: "Performance", subcategory: "Code Splitting", level: "intermediate", q: "Code splitting là gì? Các chiến lược code splitting trong web apps?", a: "Code splitting chia bundle thành các chunks nhỏ hơn, chỉ load khi cần. Chiến lược: Route-based splitting (mỗi route là chunk riêng), Component-based (lazy load components lớn), Vendor splitting (tách third-party libraries). Webpack/Vite tự động code split với dynamic import(). Giảm initial load time." },
  { id: 786, category: "Performance", subcategory: "Caching", level: "intermediate", q: "HTTP caching hoạt động như thế nào? Cache-Control headers?", a: "Cache-Control điều khiển caching behavior. Directives quan trọng: `max-age=3600` (cache 1 giờ), `no-cache` (revalidate trước khi dùng cache), `no-store` (không cache), `public`/`private`, `immutable` (không bao giờ revalidate). ETag/Last-Modified cho conditional requests. Static assets nên `max-age=31536000, immutable`." },
  { id: 787, category: "Performance", subcategory: "Performance", level: "intermediate", q: "Image optimization trong web: các kỹ thuật phổ biến?", a: "Sử dụng modern formats: WebP/AVIF nhỏ hơn JPEG/PNG 25-50%. Responsive images với srcset và sizes. Correct sizing - không serve 2000px image cho 400px container. Lazy loading cho below-fold images. CDN cho low-latency delivery. Preload critical images với `<link rel='preload'>`. Compress với tools như squoosh." },
  { id: 788, category: "Performance", subcategory: "Performance", level: "advanced", q: "Bundle analysis: cách phát hiện và giảm bundle size?", a: "Dùng webpack-bundle-analyzer hoặc vite-bundle-visualizer để xem bundle composition. Tìm: large dependencies có alternative nhỏ hơn, duplicate modules, unused code. Giải pháp: tree shaking, code splitting, dynamic imports, dùng lighter alternatives (date-fns vs moment.js), external CDN cho common libraries." },
  { id: 789, category: "Performance", subcategory: "Performance", level: "advanced", q: "Service Worker và caching strategy trong PWA là gì?", a: "Service Worker là background script intercept network requests, cho phép offline support và custom caching. Caching strategies: Cache First (offline-first), Network First (fresh data priority), Stale-While-Revalidate (serve cache, update background). Workbox từ Google đơn giản hóa Service Worker. Workbox-webpack-plugin/vite-plugin-pwa tích hợp." },
  { id: 790, category: "Performance", subcategory: "Performance", level: "advanced", q: "Virtual scrolling (windowing) là gì? Khi nào cần dùng?", a: "Virtual scrolling chỉ render items hiện đang visible trong viewport thay vì toàn bộ list. Giải quyết performance cho lists với hàng nghìn items. Libraries: `react-virtual`, `react-window`, `@tanstack/react-virtual`. Cần khi: list >100 items với complex rendering, hoặc performance profiling cho thấy list rendering là bottleneck." },

  // === SECURITY (791-800) ===
  { id: 791, category: "Security", subcategory: "XSS & CSRF", level: "intermediate", q: "XSS (Cross-Site Scripting) là gì? Các loại XSS và cách phòng chống?", a: "XSS: attacker inject malicious scripts vào web page. Loại: Stored (lưu trong DB), Reflected (trong URL), DOM-based (client-side). Phòng chống: escape user input trước khi render, dùng Content Security Policy (CSP), tránh `innerHTML`, dùng DOMPurify để sanitize HTML, HttpOnly cookies để JavaScript không access." },
  { id: 792, category: "Security", subcategory: "XSS & CSRF", level: "intermediate", q: "CSRF (Cross-Site Request Forgery) là gì? Cách phòng chống?", a: "CSRF: attacker trick user click link/form trên site độc hại, browser tự động gửi credentials đến target site. Phòng chống: CSRF tokens (random token trong form, verify server-side), SameSite cookie attribute (`Strict` hoặc `Lax`), kiểm tra Origin/Referer headers, custom headers cho AJAX requests." },
  { id: 793, category: "Security", subcategory: "CSP", level: "advanced", q: "Content Security Policy (CSP) là gì? Cách cấu hình?", a: "CSP là HTTP header định nghĩa trusted sources cho scripts, styles, images, v.v. Ngăn XSS bằng cách block inline scripts và unauthorized external scripts. Ví dụ: `Content-Security-Policy: default-src 'self'; script-src 'self' cdn.example.com`. Dùng `report-uri` để nhận violation reports. Strict CSP với nonces cho inline scripts." },
  { id: 794, category: "Security", subcategory: "Authentication", level: "intermediate", q: "OAuth 2.0 là gì? Luồng Authorization Code flow hoạt động thế nào?", a: "OAuth 2.0 là authorization framework cho phép third-party apps access user resources mà không cần password. Authorization Code flow: user redirect đến Authorization Server, login và consent, server redirect về app với code, app exchange code lấy access token. PKCE extension thêm security cho mobile/SPA." },
  { id: 795, category: "Security", subcategory: "Authentication", level: "intermediate", q: "HTTPS và TLS là gì? Tại sao bắt buộc phải dùng?", a: "HTTPS là HTTP over TLS, encrypt communication giữa browser và server. TLS (Transport Layer Security) cung cấp: encryption (không ai đọc được traffic), authentication (verify server identity qua certificates), integrity (data không bị tamper). Bắt buộc: ngăn MITM attacks, required cho HTTP/2, tăng SEO ranking, browsers warn với HTTP." },
  { id: 796, category: "Security", subcategory: "CORS", level: "intermediate", q: "CORS là gì? Tại sao browser enforce same-origin policy?", a: "Same-origin policy ngăn JavaScript từ một origin (domain+protocol+port) đọc response từ origin khác. CORS (Cross-Origin Resource Sharing) cho phép server khai báo origins được phép access. Headers: `Access-Control-Allow-Origin`, `Access-Control-Allow-Methods`. Preflight request (OPTIONS) cho non-simple requests." },
  { id: 797, category: "Security", subcategory: "Headers", level: "intermediate", q: "Security headers quan trọng trong web application là gì?", a: "Headers quan trọng: `Strict-Transport-Security` (HSTS - force HTTPS), `X-Content-Type-Options: nosniff` (prevent MIME sniffing), `X-Frame-Options` hoặc CSP frame-ancestors (prevent clickjacking), `Referrer-Policy` (control referrer info), `Permissions-Policy` (control browser features). Helmet.js tự động set tất cả trong Express." },
  { id: 798, category: "Security", subcategory: "Authentication", level: "advanced", q: "SQL Injection là gì? Cách phòng chống trong Node.js?", a: "SQL Injection: attacker inject SQL code qua user input để manipulate database queries. Ví dụ: `' OR '1'='1` bypass authentication. Phòng chống: luôn dùng parameterized queries/prepared statements, không concatenate user input vào SQL strings. ORM như Prisma, Sequelize tự động handle. Input validation thêm tầng bảo vệ." },
  { id: 799, category: "Security", subcategory: "Authentication", level: "advanced", q: "Cookie security: HttpOnly, Secure, SameSite attributes là gì?", a: "HttpOnly: JavaScript không thể access cookie qua `document.cookie`, ngăn XSS đánh cắp session. Secure: cookie chỉ gửi qua HTTPS. SameSite=Strict: không gửi cookie trong cross-site requests (ngăn CSRF). SameSite=Lax: gửi trong top-level navigation GET requests. Combination HttpOnly+Secure+SameSite=Strict là best practice cho session cookies." },
  { id: 800, category: "Security", subcategory: "Security", level: "advanced", q: "Dependency security: cách quản lý vulnerabilities trong npm packages?", a: "Dùng `npm audit` để kiểm tra known vulnerabilities, `npm audit fix` để tự fix. Dependabot hoặc Renovate tự động tạo PRs cập nhật dependencies. Snyk cung cấp deeper security scanning. Nguyên tắc: pin specific versions trong production, review breaking changes trước khi update, tránh packages ít maintained hoặc nhiều vulnerabilities." },
]
